import net.minecraft.client.render.VertexFormats; import net.minecraft.client.render.VertexFormat; import net.minecraft.client.render.VertexFormatElement; public class test_format { public static void main(String[] args) { VertexFormat format = VertexFormats.POSITION_TEXTURE_COLOR; for(VertexFormatElement element : format.getElements()) { System.out.println(element.type() + " " + element.elementUsage()); } } }
